const fs = require('fs');
const path = require('path');
const OUTPUT_DIR = path.join(__dirname, '..', 'client', 'src', 'data', 'career-questions');

function writeFile(filename, exportName, questions) {
  const lines = [`import type { CareerQuestion } from "./rrt-questions";\n\nexport const ${exportName}: CareerQuestion[] = [\n`];
  for (const q of questions) {
    const opts = q.options.map(o => JSON.stringify(o)).join(',');
    lines.push(`  { id: ${JSON.stringify(q.id)}, stem: ${JSON.stringify(q.stem)}, options: [${opts}], correctIndex: ${q.correctIndex}, rationale: ${JSON.stringify(q.rationale)}, difficulty: ${q.difficulty}, category: ${JSON.stringify(q.category)}, topic: ${JSON.stringify(q.topic)} },\n`);
  }
  lines.push(`];\n`);
  fs.writeFileSync(path.join(OUTPUT_DIR, filename), lines.join(''));
  console.log(`  ${filename}: ${questions.length} questions`);
}

